#!/usr/bin/env python3# -*- coding: utf-8 -*-import jsonimport osimport loggingimport mathimport refrom typing import Dict, List, Optional, Tuplelogger = logging.getLogger(__name__)CACHE_FILE = "data/zone_params_cache.json"class ZoneParamsCollector:    """    Class for collecting parameters of map sheets for Tver and Smolensk regions    Supports:    - Full zonal coordinates (SK-42): 6148626 6451905    - Local coordinates (from map frame): 20530 90630    - Short coordinates (last 5 digits): 48626 51905    """        ZONES_BASE = {        '4': {            'epsg': 28404,            'name': 'Zone 4 (SK-42)',            'central_meridian': 21,            'false_easting': 500000,            'false_northing': 0,            'scale_factor': 1.0,            'latitude_of_origin': 0,            'zone_number': 4,            'offset_x': 6100000,            'offset_y': 5300000,            'dx': 805,            'dy': 45        },        '5': {            'epsg': 28405,            'name': 'Zone 5 (SK-42)',            'central_meridian': 27,            'false_easting': 500000,            'false_northing': 0,            'scale_factor': 1.0,            'latitude_of_origin': 0,            'zone_number': 5,            'offset_x': 6200000,            'offset_y': 5500000,            'dx': 807,            'dy': 83        },        '6': {            'epsg': 28406,            'name': 'Zone 6 (SK-42)',            'central_meridian': 33,            'false_easting': 500000,            'false_northing': 0,            'scale_factor': 1.0,            'latitude_of_origin': 0,            'zone_number': 6,            'offset_x': 6200000,            'offset_y': 6500000,            'dx': 802,            'dy': 34        },        '7': {            'epsg': 28407,            'name': 'Zone 7 (SK-42)',            'central_meridian': 39,            'false_easting': 500000,            'false_northing': 0,            'scale_factor': 1.0,            'latitude_of_origin': 0,            'zone_number': 7,            'offset_x': 6210000,            'offset_y': 6650000,            'dx': 801,            'dy': -13        },        '8': {            'epsg': 28408,            'name': 'Zone 8 (SK-42)',            'central_meridian': 45,            'false_easting': 500000,            'false_northing': 0,            'scale_factor': 1.0,            'latitude_of_origin': 0,            'zone_number': 8,            'offset_x': 6220000,            'offset_y': 6800000,            'dx': 800,            'dy': -25        },        '9': {            'epsg': 28409,            'name': 'Zone 9 (SK-42)',            'central_meridian': 51,            'false_easting': 500000,            'false_northing': 0,            'scale_factor': 1.0,            'latitude_of_origin': 0,            'zone_number': 9,            'offset_x': 6230000,            'offset_y': 6950000,            'dx': 799,            'dy': -35        }    }    # Map sheets for Tver and Smolensk regions    MAP_SHEETS = {        # Tver region (zone 6)        'O-36-141': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'O-36-142': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'O-36-143': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'O-36-144': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'O-36-145': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'N-36-17': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'N-36-18': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'N-36-19': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'N-36-20': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'N-36-21': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'P-36-105': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'P-36-106': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'P-36-107': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'P-36-108': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'P-36-109': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},                # Smolensk region (zone 5)        'N-35-9': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'N-35-10': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'N-35-11': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-21': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-22': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-23': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-24': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-25': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-26': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-27': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-28': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'P-35-33': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'P-35-34': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'}    }    # Region boundaries    REGION_BOUNDARIES = {        'tver': {            'name': 'Tver Region',            'lat_min': 55.5,            'lat_max': 58.5,            'lon_min': 30.0,            'lon_max': 38.0        },        'smolensk': {            'name': 'Smolensk Region',            'lat_min': 53.5,            'lat_max': 56.0,            'lon_min': 30.0,            'lon_max': 35.0        },        'moscow': {            'name': 'Moscow Region',            'lat_min': 54.5,            'lat_max': 57.0,            'lon_min': 35.0,            'lon_max': 40.0        }    }    def __init__(self):        self.cache = self._load_cache()    def _load_cache(self) -> Dict:        if os.path.exists(CACHE_FILE):            try:                with open(CACHE_FILE, 'r', encoding='utf-8') as f:                    return json.load(f)            except Exception as e:                logger.error(f"Cache load error: {e}")        return {}    def _save_cache(self):        os.makedirs(os.path.dirname(CACHE_FILE), exist_ok=True)        try:            with open(CACHE_FILE, 'w', encoding='utf-8') as f:                json.dump(self.cache, f, ensure_ascii=False, indent=2)            logger.info(f"Cache saved: {CACHE_FILE}")        except Exception as e:            logger.error(f"Cache save error: {e}")    def get_zone_params(self, zone_number: str) -> Optional[Dict]:        return self.ZONES_BASE.get(zone_number)    def get_sheet_params(self, sheet_name: str) -> Optional[Dict]:        return self.MAP_SHEETS.get(sheet_name.upper())    def is_zonal_coordinate(self, x: float, y: float) -> bool:        """        Determine if coordinates are already zonal (SK-42)        Zonal coordinates: x > 5,000,000 and y > 5,000,000        Local coordinates: x < 500,000 and y < 500,000        Short coordinates: x < 100,000 and y < 100,000 (last 5 digits)        """        if x > 5000000 and y > 5000000:            return True        return False    def is_short_coordinate(self, x: float, y: float) -> bool:        """        Check if coordinates are short format (last 5 digits)        Short coordinates: x < 100,000 and y < 100,000        """        if x < 100000 and y < 100000:            return True        return False    def detect_zone_from_zonal_y(self, y: float) -> Optional[str]:        """        Detect zone from Y value in zonal coordinates        First digit of Y indicates zone number        """        y_int = int(y)        y_str = str(y_int)        if len(y_str) >= 7:            zone_digit = y_str[0]            if zone_digit in self.ZONES_BASE:                return zone_digit        return None    def reconstruct_full_coordinates_from_short(self, x: float, y: float, sheet_name: str) -> Tuple[float, float]:        """        Reconstruct full coordinates from short format (last 5 digits) using map sheet        Short coordinates: 48626 51905        Full coordinates: offset + short        """        sheet = self.get_sheet_params(sheet_name)        if not sheet:            return x, y                zone_params = self.get_zone_params(sheet['zone'])        if not zone_params:            return x, y                x_full = sheet['offset_x'] + x        y_full = sheet['offset_y'] + y                return x_full, y_full    def detect_region(self, lat: float, lon: float) -> str:        """        Detect which region the coordinates fall into        """        for region_key, bounds in self.REGION_BOUNDARIES.items():            if (bounds['lat_min'] <= lat <= bounds['lat_max'] and                bounds['lon_min'] <= lon <= bounds['lon_max']):                return region_key        return 'unknown'    def calculate_coordinates(self, x: float, y: float, zone_number: str = None, sheet_name: str = None) -> Dict:        result = {            'x_input': x,            'y_input': y,            'zone_number': zone_number,            'sheet': sheet_name,            'input_type': 'unknown',            'success': False,            'errors': [],            'region': 'unknown'        }        # Check if short coordinates with sheet name        if self.is_short_coordinate(x, y) and sheet_name:            result['input_type'] = 'short_with_sheet'            logger.info(f"Detected short coordinates with sheet: {sheet_name}, x={x}, y={y}")                        sheet = self.get_sheet_params(sheet_name)            if not sheet:                result['errors'].append(f"Map sheet {sheet_name} not found")                return result                        zone_number = sheet['zone']            result['zone_number'] = zone_number                        # Reconstruct full coordinates            x_full = sheet['offset_x'] + x            y_full = sheet['offset_y'] + y            result['x_full'] = x_full            result['y_full'] = y_full                        # Get zone parameters            zone_params = self.get_zone_params(zone_number)            if not zone_params:                result['errors'].append(f"Zone {zone_number} not found")                return result                        # Apply corrections            x_sk42 = x_full + sheet.get('dx', zone_params.get('dx', 0))            y_sk42 = y_full + sheet.get('dy', zone_params.get('dy', 0))                        result['x_sk42'] = x_sk42            result['y_sk42'] = y_sk42            result['zone'] = zone_params['name']            result['epsg'] = zone_params['epsg']            result['central_meridian'] = zone_params['central_meridian']                    # Check if zonal coordinates (full SK-42)        elif self.is_zonal_coordinate(x, y):            result['input_type'] = 'zonal_sk42'            logger.info(f"Detected zonal coordinates: x={x}, y={y}")                        if not zone_number:                zone_number = self.detect_zone_from_zonal_y(y)                if zone_number:                    result['zone_number'] = zone_number                    logger.info(f"Detected zone from Y: {zone_number}")                        zone_params = self.get_zone_params(zone_number) if zone_number else None            if not zone_params:                result['errors'].append(f"Cannot determine zone for coordinates")                return result                        x_sk42 = x            y_sk42 = y            result['x_sk42'] = x_sk42            result['y_sk42'] = y_sk42            result['zone'] = zone_params['name']            result['epsg'] = zone_params['epsg']            result['central_meridian'] = zone_params['central_meridian']                    # Local coordinates (from map frame)        else:            result['input_type'] = 'local'            logger.info(f"Detected local coordinates: x={x}, y={y}")                        if not zone_number:                result['errors'].append(f"Zone number required for local coordinates")                return result                        zone_params = self.get_zone_params(zone_number)            if not zone_params:                result['errors'].append(f"Zone {zone_number} not found")                return result                        x_full = zone_params['offset_x'] + x            y_full = zone_params['offset_y'] + y            result['x_full'] = x_full            result['y_full'] = y_full                        x_sk42 = x_full + zone_params['dx']            y_sk42 = y_full + zone_params['dy']            result['x_sk42'] = x_sk42            result['y_sk42'] = y_sk42            result['zone'] = zone_params['name']            result['epsg'] = zone_params['epsg']            result['central_meridian'] = zone_params['central_meridian']        # Convert to geographic coordinates        zone_num = int(zone_number) if zone_number else 6        y_local = result['y_sk42'] - (zone_num * 1000000)                # 1 degree latitude = 111,000 meters        # 1 degree longitude at ~55 degrees latitude = 85,000 meters        lat = result['x_sk42'] / 111000        lon = result['central_meridian'] + (y_local / 85000)                result['latitude'] = lat        result['longitude'] = lon                # Detect region        result['region'] = self.detect_region(lat, lon)                # Format DMS        result['latitude_dms'] = self._decimal_to_dms(lat, 'N')        result['longitude_dms'] = self._decimal_to_dms(lon, 'E')                result['success'] = True                # Log region detection        region_name = self.REGION_BOUNDARIES.get(result['region'], {}).get('name', 'Unknown')        logger.info(f"Coordinates: {lat:.4f}, {lon:.4f} -> {region_name}")        return result    def _decimal_to_dms(self, deg: float, direction: str) -> str:        """Convert decimal degrees to DMS format"""        if deg < 0:            deg = -deg            direction = 'S' if direction == 'N' else 'W'        degrees = int(deg)        minutes_float = (deg - degrees) * 60        minutes = int(minutes_float)        seconds = (minutes_float - minutes) * 60        return f"{degrees}°{minutes:02d}'{seconds:.1f}\" {direction}"    def detect_zone_by_coordinates(self, x: float, y: float, zone_hint: str = None, sheet_name: str = None) -> Optional[Dict]:        if zone_hint and zone_hint in self.ZONES_BASE:            return self.ZONES_BASE[zone_hint]        # If sheet name provided, use it        if sheet_name:            sheet = self.get_sheet_params(sheet_name)            if sheet:                return self.ZONES_BASE.get(sheet['zone'])        # If coordinates are zonal, detect zone from Y        if self.is_zonal_coordinate(x, y):            zone_num = self.detect_zone_from_zonal_y(y)            if zone_num:                return self.ZONES_BASE.get(zone_num)        # Try all zones for local coordinates        for zone_num, zone_params in self.ZONES_BASE.items():            x_full = zone_params['offset_x'] + x            y_full = zone_params['offset_y'] + y            x_sk42 = x_full + zone_params['dx']            y_sk42 = y_full + zone_params['dy']            lat = x_sk42 / 111000            y_local = y_sk42 - (int(zone_num) * 1000000)            lon = zone_params['central_meridian'] + (y_local / 85000)            # Check if falls into Tver or Smolensk region            if (55.5 <= lat <= 58.5 and 30 <= lon <= 38) or \               (53.5 <= lat <= 56.0 and 30 <= lon <= 35):                logger.info(f"Detected zone {zone_num}: lat={lat:.4f}, lon={lon:.4f}")                return zone_params        # Default to zone 6        logger.warning("Cannot detect zone, using zone 6 as default")        return self.ZONES_BASE.get('6')    def get_all_zones(self) -> List[str]:        return list(self.ZONES_BASE.keys())    def get_all_sheets(self) -> List[str]:        return list(self.MAP_SHEETS.keys())    def get_region_info(self, region_key: str) -> Optional[Dict]:        return self.REGION_BOUNDARIES.get(region_key)    def get_all_regions(self) -> List[str]:        return list(self.REGION_BOUNDARIES.keys())    def get_sheets_by_region(self, region_key: str) -> List[Dict]:        """Get all map sheets for a specific region"""        return [{'sheet': k, **v} for k, v in self.MAP_SHEETS.items() if v.get('region') == region_key]def get_zone_params(zone_number: str) -> Optional[Dict]:    collector = ZoneParamsCollector()    return collector.get_zone_params(zone_number)def get_sheet_params(sheet_name: str) -> Optional[Dict]:    collector = ZoneParamsCollector()    return collector.get_sheet_params(sheet_name)def detect_zone_by_coords(x: float, y: float, zone_hint: str = None, sheet_name: str = None) -> Optional[Dict]:    collector = ZoneParamsCollector()    return collector.detect_zone_by_coordinates(x, y, zone_hint, sheet_name)def calculate_coordinates(x: float, y: float, zone_number: str = None, sheet_name: str = None) -> Dict:    collector = ZoneParamsCollector()    return collector.calculate_coordinates(x, y, zone_number, sheet_name)def get_all_zones() -> List[str]:    collector = ZoneParamsCollector()    return collector.get_all_zones()def get_all_sheets() -> List[str]:    collector = ZoneParamsCollector()    return collector.get_all_sheets()def get_region_info(region_key: str) -> Optional[Dict]:    collector = ZoneParamsCollector()    return collector.get_region_info(region_key)def get_all_regions() -> List[str]:    collector = ZoneParamsCollector()    return collector.get_all_regions()def get_sheets_by_region(region_key: str) -> List[Dict]:    collector = ZoneParamsCollector()    return collector.get_sheets_by_region(region_key)